1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Conway's Game of Life - Next Generation", () => {
5	  it("should return an empty grid when given an empty grid", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell with 0 neighbors", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent live cells (each has 1 neighbor)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep a 2x2 block unchanged (still life)", () => {
15	    const result = nextGeneration([[0, 0], [1, 0], [0, 1], [1, 1]]);
16	    expect(result).toHaveLength(4);
17	    expect(result).toEqual(expect.arrayContaining([[0, 0], [1, 0], [0, 1], [1, 1]]));
18	  });
19	  it("should transform a vertical blinker into a horizontal blinker", () => {
20	    const result = nextGeneration([[0, 0], [0, 1], [0, 2]]);
21	    expect(result).toHaveLength(3);
22	    expect(result).toEqual(expect.arrayContaining([[-1, 1], [0, 1], [1, 1]]));
23	  });
24	  it.todo("should bring a dead cell to life when it has exactly 3 live neighbors");
25	  it.todo("should kill cells with more than 3 neighbors and revive corners in a full 3x3 block");
26	  it.todo("should support negative coordinates on the infinite grid");
27	});
28

1	export type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: Array<[number, number]> = [
4	  [-1, -1], [0, -1], [1, -1],
5	  [-1, 0],           [1, 0],
6	  [-1, 1],  [0, 1],  [1, 1],
7	];
8	
9	const cellKey = (x: number, y: number): string => `${x},${y}`;
10	
11	const survivesOrIsBorn = (neighborCount: number, isAlive: boolean): boolean =>
12	  neighborCount === 3 || (neighborCount === 2 && isAlive);
13	
14	export function nextGeneration(liveCells: Array<Cell>): Array<Cell> {
15	  const liveSet = new Set<string>(liveCells.map(([x, y]) => cellKey(x, y)));
16	  const neighborTallies = new Map<string, { cell: Cell; count: number }>();
17	
18	  for (const [x, y] of liveCells) {
19	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
20	      const nx = x + dx;
21	      const ny = y + dy;
22	      const k = cellKey(nx, ny);
23	      const existing = neighborTallies.get(k);
24	      if (existing) existing.count++;
25	      else neighborTallies.set(k, { cell: [nx, ny], count: 1 });
26	    }
27	  }
28	
29	  const result: Array<Cell> = [];
30	  for (const [k, { cell, count }] of neighborTallies) {
31	    if (survivesOrIsBorn(count, liveSet.has(k))) result.push(cell);
32	  }
33	  return result;
34	}
